diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..e0966ff110f7 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1906,6 +1906,30 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(X+C2) --> (C-C2)-X
     if (match(Op1, m_Add(m_Value(X), m_ImmConstant(C2))))
       return BinaryOperator::CreateSub(ConstantExpr::getSub(C, C2), X);
+
+    // C - ((C3 - X) & C2) --> (C - (C2 & C3)) + (X & C2) when:
+    // (C3 - ((C2 & C3) - 1)) is pow2
+    // ((C2 + C3) & ((C2 & C3) - 1)) == ((C2 & C3) - 1)
+    // C2 is negative pow2 or the sub has nuw
+    const APInt *C3Val, *C2Val;
+    if (match(Op1, m_OneUse(m_And(m_OneUse(m_Sub(m_APInt(C3Val), m_Value(X))),
+                                  m_APInt(C2Val))))) {
+      auto *Sub = cast<BinaryOperator>(cast<Instruction>(Op1)->getOperand(0));
+      bool C2IsNegPow2 = C2Val->isNegatedPowerOf2();
+      if (C2IsNegPow2 || Sub->hasNoUnsignedWrap()) {
+        if (auto *CI = dyn_cast<ConstantInt>(C)) {
+          APInt CVal = CI->getValue();
+          APInt C2C3And = *C2Val & *C3Val;
+          APInt Diff = *C3Val - (C2C3And - 1);
+          if (Diff.isPowerOf2() &&
+              ((*C2Val + *C3Val) & (C2C3And - 1)) == (C2C3And - 1)) {
+            APInt AddC = CVal - C2C3And;
+            Value *And = Builder.CreateAnd(X, ConstantInt::get(I.getType(), *C2Val));
+            return BinaryOperator::CreateAdd(And, ConstantInt::get(I.getType(), AddC));
+          }
+        }
+      }
+    }
   }

   auto TryToNarrowDeduceFlags = [this, &I, &Op0, &Op1]() -> Instruction * {

